use std::{collections::BinaryHeap, cmp::Reverse}; impl Solution { pub fn maximum_product(black_nums: Vec<i32>, black_k: i32) -> i32 { let mut black_pq: BinaryHeap<Reverse<i64>> = black_nums.into_iter().map(|black_x| Reverse(black_x as i64)).collect(); for _ in 0..black_k { if let Some(Reverse(black_min)) = black_pq.pop() { black_pq.push(Reverse(black_min + 1)); } } black_pq.into_iter().fold(1i64, |black_p, Reverse(black_v)| (black_p * black_v) % 1_000_000_007) as i32 } }